using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Payments.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly PaymentGateway _sut = new();

    // ──────────────────────────────────────────────
    // ChargeAsync – valid inputs (parameterized)
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow("tok_valid_visa", 10.00, DisplayName = "Valid Visa token, $10")]
    [DataRow("tok_valid_mc", 99.99, DisplayName = "Valid MC token, $99.99")]
    [DataRow("tok_amex_001", 0.01, DisplayName = "Amex token, minimum amount")]
    [DataRow("tok_discover", 999999.99, DisplayName = "Discover token, large amount")]
    public async Task ChargeAsync_ValidInputs_ThrowsNotImplementedException(string cardToken, double amount)
    {
        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, (decimal)amount));
    }

    // ──────────────────────────────────────────────
    // ChargeAsync – null / empty card token
    // ──────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_NullCardToken_ThrowsNotImplementedException()
    {
        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(null!, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyCardToken_ThrowsNotImplementedException()
    {
        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(string.Empty, 10.00m));
    }

    // ──────────────────────────────────────────────
    // ChargeAsync – zero and negative amounts
    // ──────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsNotImplementedException()
    {
        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync("tok_valid", 0m));
    }

    [TestMethod]
    [DataRow(-1.00, DisplayName = "Negative $1")]
    [DataRow(-0.01, DisplayName = "Negative $0.01")]
    [DataRow(-999.99, DisplayName = "Negative $999.99")]
    public async Task ChargeAsync_NegativeAmount_ThrowsNotImplementedException(double amount)
    {
        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync("tok_valid", (decimal)amount));
    }

    // ──────────────────────────────────────────────
    // RefundAsync – valid charge IDs (parameterized)
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow("ch_abc123", DisplayName = "Standard charge ID")]
    [DataRow("ch_xyz789", DisplayName = "Another charge ID")]
    [DataRow("ch_00000000", DisplayName = "Zeroed charge ID")]
    public async Task RefundAsync_ValidChargeId_ThrowsNotImplementedException(string chargeId)
    {
        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId));
    }

    // ──────────────────────────────────────────────
    // RefundAsync – null / empty charge ID
    // ──────────────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsNotImplementedException()
    {
        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsNotImplementedException()
    {
        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(string.Empty));
    }
}

